python3 -c "
import json
keywords = ['Chelsea', 'AFCON', 'Man United', 'Marc Guehi', 'Starlink', 'Greenland', 'Iran', 'Venezuela', 'Australian Open', 'NFL', 'Ukraine', 'TikTok', 'Syria', 'Champions League']
with open('articles/2025/12/27/articles.jsonl') as f:
    articles = [json.loads(line) for line in f]
print(f'Total articles: {len(articles)}')
for kw in keywords:
    count = 0
    titles = []
    for i, a in enumerate(articles):
        title = a.get('title', '') or ''
        if kw.lower() in title.lower():
            count += 1
            if len(titles) < 3:
                titles.append(f'  {title[:120]}')
    if count > 0:
        print(f'\\n--- {kw} ({count}) ---')
        for t in titles:
            print(t)
" 2>/dev/null
